from pydantic import BaseModel, Field, field_validator, model_validator
from datetime import date
from typing import Literal


class EventExtraction(BaseModel):
    title: str = Field(min_length=1, max_length=200)
    start_date: date
    end_date: date
    category: Literal["conference", "webinar", "workshop", "meetup"]
    max_attendees: int = Field(ge=1, le=100_000)
    registration_url: str | None = None
    confidence: float = Field(ge=0.0, le=1.0, description="Model's confidence 0–1")

    @field_validator("title")
    @classmethod
    def title_not_placeholder(cls, v: str) -> str:
        placeholders = {"n/a", "tbd", "unknown", "none", "null"}
        if v.lower().strip() in placeholders:
            raise ValueError(f"title is a placeholder value: {v!r}")
        return v.strip()

    @field_validator("registration_url")
    @classmethod
    def validate_url(cls, v: str | None) -> str | None:
        if v is not None and not v.startswith(("http://", "https://")):
            raise ValueError(f"registration_url must be a full URL, got: {v!r}")
        return v

    @model_validator(mode="after")
    def end_after_start(self) -> "EventExtraction":
        if self.end_date < self.start_date:
            raise ValueError(
                f"end_date ({self.end_date}) must be >= start_date ({self.start_date})"
            )
        return self


# Example: model returns wrong dates — Pydantic catches it
try:
    event = EventExtraction(
        title="PyCon 2025",
        start_date=date(2025, 5, 15),
        end_date=date(2025, 5, 10),   # before start!
        category="conference",
        max_attendees=3000,
        confidence=0.92,
    )
except Exception as e:
    print(e)  # end_date (2025-05-10) must be >= start_date (2025-05-15)

import json
from pydantic import ValidationError
from openai import OpenAI

client = OpenAI()


def extract_with_retry(
    text: str,
    model_class: type,
    system_prompt: str,
    max_retries: int = 3,
) -> object:
    messages = [
        {"role": "system", "content": system_prompt},
        {"role": "user", "content": text},
    ]

    for attempt in range(max_retries):
        response = client.chat.completions.create(
            model="gpt-4o-mini",
            response_format={"type": "json_object"},
            messages=messages,
        )
        raw_text = response.choices[0].message.content
        messages.append({"role": "assistant", "content": raw_text})

        try:
            data = json.loads(raw_text)
            return model_class(**data)
        except (json.JSONDecodeError, ValidationError) as e:
            if attempt == max_retries - 1:
                raise RuntimeError(f"Extraction failed after {max_retries} attempts: {e}")
            # Feed the error back to the model
            messages.append({
                "role": "user",
                "content": (
                    f"Your previous response failed validation with this error:\n{e}\n\n"
                    "Please fix the JSON and try again."
                ),
            })
    raise RuntimeError("unreachable")


event = extract_with_retry(
    text="DataFest runs May 15–10, 2025 in NYC. Max 500 people. conference.",
    model_class=EventExtraction,
    system_prompt=(
        'Extract event info as JSON with keys: title, start_date (YYYY-MM-DD), '
        'end_date (YYYY-MM-DD), category, max_attendees, confidence (0.0–1.0).'
    ),
)
print(event)

import json
from pydantic import BaseModel, ValidationError
from openai import OpenAI
from dataclasses import dataclass, field
from typing import Any

client = OpenAI()


@dataclass
class PipelineResult:
    success: bool
    value: Any = None
    errors: list[str] = field(default_factory=list)


def validate_pipeline(
    raw_text: str,
    schema: type[BaseModel],
    business_rules: list,   # list of callables: (instance) -> str | None
    max_retries: int = 3,
) -> PipelineResult:
    errors = []

    # Layer 1+2: Pydantic
    try:
        data = json.loads(raw_text)
        instance = schema(**data)
    except json.JSONDecodeError as e:
        return PipelineResult(success=False, errors=[f"Invalid JSON: {e}"])
    except ValidationError as e:
        return PipelineResult(success=False, errors=[str(e)])

    # Layer 3: Business rules
    for rule in business_rules:
        error_msg = rule(instance)
        if error_msg:
            errors.append(error_msg)

    if errors:
        return PipelineResult(success=False, errors=errors)

    return PipelineResult(success=True, value=instance)


# Usage
class Product(BaseModel):
    name: str
    price: float
    sku: str

KNOWN_SKUS = {"A100", "B200", "C300"}

def rule_sku_exists(p: Product) -> str | None:
    if p.sku not in KNOWN_SKUS:
        return f"Unknown SKU: {p.sku}"
    return None

def rule_positive_price(p: Product) -> str | None:
    if p.price <= 0:
        return f"Price must be positive, got {p.price}"
    return None

raw = '{"name": "Widget", "price": 9.99, "sku": "A100"}'
result = validate_pipeline(raw, Product, [rule_sku_exists, rule_positive_price])
if result.success:
    print("Valid:", result.value)
else:
    print("Errors:", result.errors)

import re
from openai import OpenAI

client = OpenAI()


def validate_code_output(code: str, language: str = "python") -> tuple[bool, str]:
    """Heuristic checks for LLM-generated code."""
    errors = []

    # 1. Non-empty
    if not code.strip():
        errors.append("Output is empty.")

    # 2. For Python: must be syntactically valid
    if language == "python":
        import ast
        try:
            ast.parse(code)
        except SyntaxError as e:
            errors.append(f"Python syntax error: {e}")

    # 3. No placeholder patterns
    placeholders = re.findall(r"\b(TODO|FIXME|YOUR_CODE_HERE|pass\s*#\s*todo)", code, re.I)
    if placeholders:
        errors.append(f"Output contains placeholders: {placeholders}")

    # 4. No obvious API hallucinations for common libraries
    # (extend with domain-specific patterns)
    hallucinated = re.findall(r"openai\.v2\.|langchain\.legacy\.", code)
    if hallucinated:
        errors.append(f"Suspicious API references: {hallucinated}")

    return len(errors) == 0, "\n".join(errors)


def validate_summary_length(
    summary: str,
    original_text: str,
    max_ratio: float = 0.3,
) -> tuple[bool, str]:
    """Summary should be shorter than the original."""
    ratio = len(summary) / max(len(original_text), 1)
    if ratio > max_ratio:
        return False, f"Summary is {ratio:.0%} of original (max {max_ratio:.0%})"
    return True, ""

from pydantic import BaseModel, Field
from typing import Literal
import instructor
from openai import OpenAI

client = instructor.from_openai(OpenAI())


class ClassificationResult(BaseModel):
    category: Literal["complaint", "question", "feedback", "other"]
    confidence: float = Field(ge=0.0, le=1.0)
    explanation: str


AUTO_ACCEPT_THRESHOLD = 0.85
HUMAN_REVIEW_THRESHOLD = 0.60


def classify_and_route(text: str) -> dict:
    result = client.chat.completions.create(
        model="gpt-4o-mini",
        response_model=ClassificationResult,
        messages=[
            {"role": "system", "content": "Classify the customer message."},
            {"role": "user", "content": text},
        ],
    )

    if result.confidence >= AUTO_ACCEPT_THRESHOLD:
        action = "auto_process"
    elif result.confidence >= HUMAN_REVIEW_THRESHOLD:
        action = "human_review"
    else:
        action = "discard_and_default"

    return {"category": result.category, "confidence": result.confidence, "action": action}


print(classify_and_route("When will my order arrive?"))
# → {'category': 'question', 'confidence': 0.97, 'action': 'auto_process'}
